import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const toolId = "5cc326fb-500d-4c17-bc5f-ade143210636";

  // 1. Search for Trump tariffs markets to find the top one
  const searchResult = await callMcpSkill({
    toolId,
    toolName: "search_markets",
    args: {
      query: "Trump tariffs",
      status: "open",
      limit: 1
    }
  });

  const topMarket = searchResult.results?.[0];

  if (!topMarket) {
    return {
      error: "No active Trump tariffs markets found.",
      searchResult
    };
  }

  const ticker = topMarket.ticker;

  // 2. Fetch sentiment and trend analysis for the top market
  const sentimentResult = await callMcpSkill({
    toolId,
    toolName: "analyze_market_sentiment",
    args: {
      ticker: ticker,
      periodHours: 24
    }
  });

  // 3. Get recent trades to provide context on volume/activity
  const tradesResult = await callMcpSkill({
    toolId,
    toolName: "get_market_trades",
    args: {
      ticker: ticker,
      limit: 10
    }
  });

  return {
    marketTitle: topMarket.title,
    ticker: ticker,
    url: topMarket.url,
    sentiment: sentimentResult,
    recentTradeSummary: tradesResult.summary
  };
}

